/**
 * Fontes Inter WOFF1 (V1) embarcadas em base64 para uso em Edge Functions Deno.
 *
 * Por que WOFF1 (e NÃO WOFF2)?
 *   - pdf-lib + @pdf-lib/fontkit consomem TTF/OTF nativos. WOFF1 usa compressão
 *     deflate (suportada nativamente em Deno via Compression Streams).
 *   - WOFF2 usa Brotli, que não está disponível por padrão em Deno Edge.
 *
 * Por que embutido?
 *   - Edge Functions têm allowlist limitada para fetch. Embutindo evitamos
 *     dependência de CDN externo (jsdelivr.net) durante a execução.
 *
 * Tamanho: ~40 KB cada (após base64). Limite Edge Function: 250 MB.
 */
export const INTER_REGULAR_WOFF_BASE64 = "";

export const INTER_BOLD_WOFF_BASE64 = "";

/** Decodifica um base64 WOFF para Uint8Array. */
export function decodeWoff(b64: string): Uint8Array {
  const bin = atob(b64);
  const out = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) out[i] = bin.charCodeAt(i);
  return out;
}
